using System;
using System.Collections.Generic;
using System.Linq;
using Microsoft.Build.Logging.StructuredLogger;

class Program
{
    static void Main(string[] args)
    {
        var binlogPath = args.Length > 0 ? args[0] : "build.binlog";
        var build = BinaryLog.ReadBuild(binlogPath);

        Console.WriteLine("=== BUILD RESULT ===");
        Console.WriteLine($"Succeeded: {build.Succeeded}");
        Console.WriteLine();

        // Collect all errors
        var errors = new List<(string project, string code, string message, string file, int line)>();
        var warnings = new List<(string project, string code, string message, string file, int line)>();

        build.VisitAllChildren<Error>(e =>
        {
            var proj = FindParentProject(e);
            errors.Add((proj, e.Code ?? "", e.Text ?? e.ToString(), e.File ?? "", e.LineNumber));
        });

        build.VisitAllChildren<Warning>(w =>
        {
            var proj = FindParentProject(w);
            warnings.Add((proj, w.Code ?? "", w.Text ?? w.ToString(), w.File ?? "", w.LineNumber));
        });

        Console.WriteLine($"=== ERRORS ({errors.Count}) ===");
        foreach (var g in errors.GroupBy(e => e.project))
        {
            Console.WriteLine($"\n--- Project: {g.Key} ---");
            foreach (var e in g)
            {
                Console.WriteLine($"  [{e.code}] {e.file}({e.line}): {e.message}");
            }
        }

        Console.WriteLine($"\n=== WARNINGS ({warnings.Count}) ===");
        foreach (var g in warnings.GroupBy(w => w.project).Take(20))
        {
            Console.WriteLine($"\n--- Project: {g.Key} ---");
            foreach (var w in g.Take(10))
            {
                Console.WriteLine($"  [{w.code}] {w.file}({w.line}): {w.message}");
            }
            if (g.Count() > 10) Console.WriteLine($"  ... and {g.Count() - 10} more warnings");
        }

        // Show project dependency failures
        Console.WriteLine("\n=== PROJECT BUILD RESULTS ===");
        build.VisitAllChildren<Project>(p =>
        {
            if (p.Children != null)
            {
                bool hasError = false;
                p.VisitAllChildren<Error>(e => hasError = true);
                if (hasError)
                {
                    Console.WriteLine($"  FAILED: {p.Name} [{p.TargetFramework}]");
                }
            }
        });
    }

    static string FindParentProject(BaseNode node)
    {
        var current = node.Parent;
        while (current != null)
        {
            if (current is Project p) return p.Name ?? "(unknown)";
            current = current.Parent;
        }
        return "(unknown)";
    }
}
