{
    static void Main(string[] args)
    {
        var binlogPath = args.Length > 0 ? args[0] : "build.binlog";
        var build = BinaryLog.ReadBuild(binlogPath);

        // Show all projects and their dependencies
        Console.WriteLine("=== ALL PROJECTS IN BUILD ===");
        build.VisitAllChildren<Project>(p =>
        {
            Console.WriteLine($"  Project: {p.Name} [TFM: {p.TargetFramework}]");
        });

