        Console.WriteLine("\n=== DETAILED ERROR CONTEXT ===");
        build.VisitAllChildren<Error>(e =>
        {
            var proj = FindParentProject(e);
            Console.WriteLine($"Project: {proj}");
            Console.WriteLine($"  Code: {e.Code}");
            Console.WriteLine($"  File: {e.File}");
            Console.WriteLine($"  Line: {e.LineNumber}, Col: {e.ColumnNumber}");
            Console.WriteLine($"  Message: {e.Text}");
            Console.WriteLine();
        });

        // Check for NuGet restore issues 
        Console.WriteLine("=== NUGET / RESTORE MESSAGES ===");
        build.VisitAllChildren<Message>(m =>
        {
            var text = m.Text ?? "";
            if (text.Contains("Newtonsoft", StringComparison.OrdinalIgnoreCase) ||
                text.Contains("PackageReference", StringComparison.OrdinalIgnoreCase) ||
                text.Contains("restore", StringComparison.OrdinalIgnoreCase) ||
                text.Contains("NU", StringComparison.OrdinalIgnoreCase))
            {
                Console.WriteLine($"  {text.Substring(0, Math.Min(text.Length, 200))}");
            }
        });

        // Check for project references
        Console.WriteLine("\n=== PROJECT REFERENCES & ITEMS ===");
        build.VisitAllChildren<Item>(item =>
        {
            if (item.Name == "ProjectReference" || item.Name == "PackageReference")
            {
                var proj = FindParentProject(item);
                Console.WriteLine($"  [{proj}] {item.Name}: {item.Text}");
            }
        });

        // Check all AddItem groups
        Console.WriteLine("\n=== ADD ITEMS (PackageReference) ===");
        build.VisitAllChildren<AddItem>(ai =>
        {
            if (ai.Name == "PackageReference")
            {
                var proj = FindParentProject(ai);
                Console.WriteLine($"  [{proj}] AddItem PackageReference:");
                foreach (var child in ai.Children)
                {
                    if (child is Item item)
                        Console.WriteLine($"    {item.Text}");
                }
            }
        });
    }

    static string FindParentProject(BaseNode node)
    {
        var current = node.Parent;
        while (current != null)
        {
            if (current is Project p) return p.Name ?? "(unknown)";
            current = current.Parent;
        }
        return "(unknown)";
    }
}
